css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; display: flex; justify-content: center; padding: 40px 20px; min-height: 100vh; }
.app { width: 100%; max-width: 400px; text-align: center; }
h1 { font-size: 26px; font-weight: 800; margin-bottom: 8px; }
.subtitle { color: rgba(255,255,255,0.4); font-size: 13.5px; margin-bottom: 24px; }
.dice-count { display: flex; align-items: center; justify-content: center; gap: 20px; margin-bottom: 28px; }
.dice-count button { width: 40px; height: 40px; border-radius: 50%; background: rgba(255,255,255,0.06); border: none; color: white; font-size: 20px; font-weight: 700; cursor: pointer; }
.dice-count span { font-size: 16px; font-weight: 700; min-width: 70px; }
.dice-area { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; margin-bottom: 24px; min-height: 90px; }
.die { width: 80px; height: 80px; background: white; border-radius: 16px; display: grid; grid-template-columns: 1fr 1fr 1fr; grid-template-rows: 1fr 1fr 1fr; padding: 12px; box-shadow: 0 10px 30px rgba(0,0,0,0.3); transition: transform 0.5s; }
.die.rolling { animation: shake 0.5s; }
@keyframes shake { 0%,100% { transform: rotate(0); } 25% { transform: rotate(15deg); } 75% { transform: rotate(-15deg); } }
.dot { width: 12px; height: 12px; background: #1a1a2e; border-radius: 50%; align-self: center; justify-self: center; }
.total { font-size: 20px; font-weight: 800; color: #facc15; margin-bottom: 24px; }
.roll-btn { background: linear-gradient(135deg, #6366f1, #818cf8); border: none; color: white; padding: 18px 40px; border-radius: 999px; font-size: 16px; font-weight: 800; cursor: pointer; box-shadow: 0 14px 30px rgba(99,102,241,0.3); margin-bottom: 32px; }
h2 { font-size: 16px; font-weight: 700; text-align: left; margin-bottom: 12px; }
.history { display: flex; flex-direction: column; gap: 8px; }
.history-item { display: flex; justify-content: space-between; background: rgba(255,255,255,0.04); border-radius: 10px; padding: 12px 16px; font-size: 13.5px; font-weight: 600; }
.history-item span:last-child { color: #facc15; font-weight: 800; }

js:
let diceCount = 2;
let history = [];

const dotPositions = {
  1: [5],
  2: [1, 9],
  3: [1, 5, 9],
  4: [1, 3, 7, 9],
  5: [1, 3, 5, 7, 9],
  6: [1, 3, 4, 6, 7, 9]
};

function renderDice(values) {
  const area = document.getElementById('diceArea');
  area.innerHTML = '';
  values.forEach(val => {
    const die = document.createElement('div');
    die.className = 'die';
    for (let i = 1; i <= 9; i++) {
      const cell = document.createElement('div');
      if (dotPositions[val].includes(i)) cell.className = 'dot';
      die.appendChild(cell);
    }
    area.appendChild(die);
  });
}

function changeDiceCount(delta) {
  diceCount = Math.max(1, Math.min(6, diceCount + delta));
  document.getElementById('diceCountLabel').textContent = `${diceCount} Zar`;
  renderDice(Array(diceCount).fill(1));
  updateTotal(Array(diceCount).fill(1));
}

function updateTotal(values) {
  const sum = values.reduce((a, b) => a + b, 0);
  document.getElementById('total').textContent = `Toplam: ${sum}`;
  return sum;
}

function rollDice() {
  document.querySelectorAll('.die').forEach(d => d.classList.add('rolling'));
  setTimeout(() => {
    const values = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    renderDice(values);
    const sum = updateTotal(values);
    addHistory(values, sum);
  }, 400);
}

function addHistory(values, sum) {
  history.unshift({ values, sum });
  if (history.length > 5) history.pop();
  const container = document.getElementById('history');
  container.innerHTML = '';
  history.forEach(h => {
    const div = document.createElement('div');
    div.className = 'history-item';
    div.innerHTML = `<span>${h.values.join(' + ')}</span><span>${h.sum}</span>`;
    container.appendChild(div);
  });
}

renderDice(Array(diceCount).fill(1));
updateTotal(Array(diceCount).fill(1));
